// Construye el digest semanal completo para el manager.
// Agrupa métricas relevantes: progreso, riesgo, carga, vencidos.
const allItems = $input.all();
if (allItems.length < 2) return [];

const tickets = allItems[0].json;
const managers = allItems[1].json;

if (!Array.isArray(managers) || managers.length === 0) return [];
if (!Array.isArray(tickets) || tickets.length === 0) return [];

// Calcular fechas de la semana
const today = new Date();
const lastMonday = new Date(today);
lastMonday.setDate(today.getDate() - 7);

// Métricas globales
const total = tickets.length;
const done = tickets.filter(t => t.status === 'done').length;
const inProgress = tickets.filter(t => t.status === 'in_progress').length;
const todo = tickets.filter(t => t.status === 'todo').length;
const backlog = tickets.filter(t => t.status === 'backlog').length;
const highRisk = tickets.filter(t => t.risk_pct > 60);
const overdue = tickets.filter(t => t.deadline && new Date(t.deadline) < today && t.status !== 'done');
const completionPct = total > 0 ? Math.round((done / total) * 100) : 0;
const totalHours = tickets.reduce((a, t) => a + (t.estimate_hours || 0), 0);
const doneHours = tickets.filter(t => t.status === 'done').reduce((a, t) => a + (t.estimate_hours || 0), 0);

// Por proyecto
const byProject = new Map();
for (const t of tickets) {
  const pName = t.projects?.name || 'Sin proyecto';
  const pId = t.project_id || 'unknown';
  if (!byProject.has(pId)) byProject.set(pId, { name: pName, total: 0, done: 0, inProgress: 0, highRisk: 0 });
  const p = byProject.get(pId);
  p.total++;
  if (t.status === 'done') p.done++;
  if (t.status === 'in_progress') p.inProgress++;
  if (t.risk_pct > 60) p.highRisk++;
}

// Por developer (solo los con tickets)
const byMember = new Map();
for (const t of tickets) {
  if (!t.assignee_id) continue;
  const mName = t.members?.name || 'Sin nombre';
  const mLoad = t.members?.current_load ?? 0;
  if (!byMember.has(t.assignee_id)) byMember.set(t.assignee_id, { name: mName, load: mLoad, total: 0, done: 0, inProgress: 0, overdue: 0 });
  const m = byMember.get(t.assignee_id);
  m.total++;
  if (t.status === 'done') m.done++;
  if (t.status === 'in_progress') m.inProgress++;
  if (t.deadline && new Date(t.deadline) < today && t.status !== 'done') m.overdue++;
}

// Generar filas HTML
const projectRows = [...byProject.values()].map(p => {
  const pct = p.total > 0 ? Math.round((p.done / p.total) * 100) : 0;
  return `<tr>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${p.name}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center">${p.done}/${p.total}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center">${p.inProgress}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center;font-weight:600">${pct}%</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center;color:${p.highRisk > 0 ? '#dc2626' : '#16a34a'}">${p.highRisk}</td>
  </tr>`;
}).join('');

const memberRows = [...byMember.values()].map(m => {
  const loadColor = m.load > 80 ? '#dc2626' : m.load > 60 ? '#d97706' : '#16a34a';
  return `<tr>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${m.name}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center;color:${loadColor};font-weight:600">${m.load}%</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center">${m.inProgress}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center">${m.done}/${m.total}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;text-align:center;color:${m.overdue > 0 ? '#dc2626' : '#16a34a'}">${m.overdue}</td>
  </tr>`;
}).join('');

const highRiskRows = highRisk.map(t => {
  return `<tr>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.title}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.members?.name || '—'}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.projects?.name || '—'}</td>
    <td style="padding:8px 12px;border-top:1px solid #e5e5e5;color:#dc2626;font-weight:700">${t.risk_pct}%</td>
  </tr>`;
}).join('');

const weekLabel = `semana del ${lastMonday.toLocaleDateString('es-SV', { day: '2-digit', month: 'short' })} al ${today.toLocaleDateString('es-SV', { day: '2-digit', month: 'short' })}`;

const digestHtml = `<div style="font-family:sans-serif;max-width:700px;margin:0 auto">
  <h1 style="color:#111;border-bottom:3px solid #111;padding-bottom:12px">📊 Digest semanal del equipo</h1>
  <p style="color:#6b7280">${weekLabel}</p>

  <div style="display:flex;gap:16px;margin:20px 0;flex-wrap:wrap">
    <div style="flex:1;min-width:120px;background:#f5f5f5;padding:16px;border-radius:8px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#111">${completionPct}%</div>
      <div style="color:#6b7280;font-size:13px">completado</div>
    </div>
    <div style="flex:1;min-width:120px;background:#f0fdf4;padding:16px;border-radius:8px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#16a34a">${done}</div>
      <div style="color:#6b7280;font-size:13px">tickets done</div>
    </div>
    <div style="flex:1;min-width:120px;background:#eff6ff;padding:16px;border-radius:8px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#2563eb">${inProgress}</div>
      <div style="color:#6b7280;font-size:13px">en progreso</div>
    </div>
    ${highRisk.length > 0 ? `<div style="flex:1;min-width:120px;background:#fef2f2;padding:16px;border-radius:8px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#dc2626">${highRisk.length}</div>
      <div style="color:#6b7280;font-size:13px">riesgo alto</div>
    </div>` : ''}
    ${overdue.length > 0 ? `<div style="flex:1;min-width:120px;background:#fff7ed;padding:16px;border-radius:8px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#d97706">${overdue.length}</div>
      <div style="color:#6b7280;font-size:13px">vencidos</div>
    </div>` : ''}
  </div>

  <h2 style="color:#111;margin-top:28px">Por proyecto</h2>
  <table style="border-collapse:collapse;width:100%">
    <tr style="background:#111;color:#fff">
      <th style="padding:8px 12px;text-align:left">Proyecto</th>
      <th style="padding:8px 12px;text-align:center">Avance</th>
      <th style="padding:8px 12px;text-align:center">En curso</th>
      <th style="padding:8px 12px;text-align:center">%</th>
      <th style="padding:8px 12px;text-align:center">Riesgo alto</th>
    </tr>
    ${projectRows}
  </table>

  <h2 style="color:#111;margin-top:28px">Carga del equipo</h2>
  <table style="border-collapse:collapse;width:100%">
    <tr style="background:#111;color:#fff">
      <th style="padding:8px 12px;text-align:left">Developer</th>
      <th style="padding:8px 12px;text-align:center">Carga</th>
      <th style="padding:8px 12px;text-align:center">En curso</th>
      <th style="padding:8px 12px;text-align:center">Completados</th>
      <th style="padding:8px 12px;text-align:center">Vencidos</th>
    </tr>
    ${memberRows}
  </table>

  ${highRisk.length > 0 ? `<h2 style="color:#dc2626;margin-top:28px">⚠️ Tickets en riesgo alto (>${60}%)</h2>
  <table style="border-collapse:collapse;width:100%">
    <tr style="background:#dc2626;color:#fff">
      <th style="padding:8px 12px;text-align:left">Ticket</th>
      <th style="padding:8px 12px;text-align:left">Asignado a</th>
      <th style="padding:8px 12px;text-align:left">Proyecto</th>
      <th style="padding:8px 12px;text-align:center">Riesgo</th>
    </tr>
    ${highRiskRows}
  </table>` : '<p style="color:#16a34a;margin-top:20px">✅ Sin tickets en riesgo alto esta semana.</p>'}

  <p style="color:#6b7280;font-size:13px;margin-top:32px;border-top:1px solid #e5e5e5;padding-top:16px">
    Horas comprometidas: <strong>${totalHours}h total</strong> · <strong>${doneHours}h entregadas</strong> · <strong>${totalHours - doneHours}h pendientes</strong><br>
    Meeting → Tickets PM · Cursor Buildathon El Salvador 2026
  </p>
</div>`;

return managers.map(manager => ({
  json: {
    manager_id: manager.id,
    manager_name: manager.name,
    manager_email: manager.email,
    week_label: weekLabel,
    total_tickets: total,
    done_tickets: done,
    high_risk_count: highRisk.length,
    overdue_count: overdue.length,
    digest_html: digestHtml
  }
}));
